/// Write all built-in programs to ALFS, always overwriting.
/// Call this after `alfs::mount()` succeeds.
pub fn seed_alfs() {
    for prog in PROGRAMS {
        let _ = crate::alfs::write_file(prog.name, prog.data, crate::alfs::TYPE_ALEPH);
    }
    for prog in IMASM_PROGRAMS {
        let _ = crate::alfs::write_file(prog.name, prog.data, crate::alfs::TYPE_ALEPH);
    }
}

/// Look up an IMASM program by name and return its text, or None.
pub fn load_imasm(name: &str) -> Option<&'static str> {
    IMASM_PROGRAMS.iter()
        .find(|p| p.name == name || p.name.trim_end_matches(".imasm") == name)
        .and_then(|p| core::str::from_utf8(p.data).ok())
}
